solutions.cpp:
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<int> deleteHead(vector<int>& head) {
        if (head.empty()) return {};
        vector<int> res(head.begin() + 1, head.end());
        return res;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> head(n);
    for (int i = 0; i < n; ++i) cin >> head[i];
    Solution sol;
    vector<int> ans = sol.deleteHead(head);
    cout << ans.size() << "\n";
    if (!ans.empty()) {
        for (size_t i = 0; i < ans.size(); ++i) {
            cout << ans[i];
            if (i + 1 < ans.size()) cout << ' ';
        }
        cout << "\n";
    }
    return 0;
}
